#!/usr/bin/env python3
from __future__ import annotations
import argparse, json, shutil, sys, tempfile
from pathlib import Path
ROOT=Path(__file__).resolve().parents[3]
if str(ROOT) not in sys.path: sys.path.insert(0,str(ROOT))
from tools.resolution.soil._resolution_common import *

def main(argv=None):
 ap=argparse.ArgumentParser();
 for n in ['accountability-root','assurance-root','registry-root','certification-root','archive-root','preservation-root','reconciliation-root','federation-root','discovery-root','published-root','ops-root','out-root','base-public-url']: ap.add_argument('--'+n,required=True)
 ap.add_argument('--accountability-id'); ap.add_argument('--resolution-id'); a=ap.parse_args(argv)
 if not validate_base_public_url(a.base_public_url): print(json.dumps({'resolution_allowed':False,'reasons':['invalid base_public_url']})); return 1
 aid=a.accountability_id or load_current_accountability(a.accountability_root)['active_accountability_id']
 am=load_accountability_manifest(a.accountability_root,aid); ar=load_accountability_receipt(a.accountability_root,aid)
 ass_id=load_current_assurance(a.assurance_root)['active_assurance_id']; reg_id=load_current_registry(a.registry_root)['active_registry_id']
 cert_id=load_current_certification(a.certification_root)['active_certification_id']; rel_id=load_current_release(a.published_root)['active_release_id']
 certs=load_certificate_status(a.registry_root,reg_id).get('certificate_status','active')
 reasons=[]
 if am.get('accountability_status')!='PUBLIC_ACCOUNTABILITY_READY': reasons.append('bad accountability status')
 if certs!='active': reasons.append('certificate not active')
 if release_is_retracted(a.published_root,rel_id): reasons.append('release retracted')
 if reasons: print(json.dumps({'resolution_allowed':False,'accountability_id':aid,'release_id':rel_id,'reasons':reasons},sort_keys=True)); return 1
 adir=Path(a.out_root)/f'resolution/soil/adjudications/{aid}'
 notices=sorted(adir.glob('*.adjudication_notice.json')) if adir.exists() else []
 recs={p.name.replace('.adjudication_receipt.json',''):load_json(p) for p in sorted(adir.glob('*.adjudication_receipt.json'))} if adir.exists() else {}
 items=[]
 for n in notices:
  j=load_json(n); i=j['adjudication_id'];
  if i not in recs: print(json.dumps({'resolution_allowed':False,'reasons':['missing adjudication receipt '+i]})); return 1
  items.append(j)
 rid=a.resolution_id or ('soil-resolution-'+stable_payload_hash({'aid':aid,'adjs':[sha256_file(p) for p in notices]})[:16])
 rid=sanitize_id(rid)
 out=Path(a.out_root)/f'resolution/soil/cycles/{rid}'; tmp=Path(tempfile.mkdtemp(prefix='res.',dir=str(out.parent)))
 counts={'feedback':0,'challenge':0,'correction':0}
 for i in items: counts[i['target_type']]+=1
