 ev={'schema_version':'kfm.v1','object_type':'SoilCorrectionEvidenceReviewRegistry','domain':'soil','resolution_id':rid,'accountability_id':aid,'release_id':rel_id,'evidence_reviews':[{'adjudication_id':i['adjudication_id'],'target_type':i['target_type'],'target_id':i['target_id'],'evidence_review_required':True,'evidence_review_decision':i['evidence_review_decision'],'evidence_refs':i['evidence_refs'],'evidence_bound_resolution_required':True,'public_submission_is_truth_source':False,'receipt_ref':f"resolution/soil/adjudications/{aid}/{i['adjudication_id']}.adjudication_receipt.json",'receipt_sha256':'sha256:'+sha256_file(adir/f"{i['adjudication_id']}.adjudication_receipt.json")} for i in sorted(items,key=lambda x:x['adjudication_id'])],'insufficient_evidence_count':0,'inconclusive_evidence_count':sum(1 for i in items if i['evidence_review_decision']=='inconclusive'),'sufficient_evidence_count':sum(1 for i in items if i['evidence_review_decision']=='sufficient')}
