 write_json_atomic(tmp/'feedback_resolution_report.json',{'schema_version':'kfm.v1','object_type':'SoilFeedbackResolutionReport','entries':[]}); write_json_atomic(tmp/'challenge_resolution_report.json',{'schema_version':'kfm.v1','object_type':'SoilChallengeResolutionReport','entries':[],'truth_policy':{'challenge_is_not_truth_source':True,'evidence_bound_resolution_required':True}}); write_json_atomic(tmp/'correction_resolution_report.json',{'schema_version':'kfm.v1','object_type':'SoilCorrectionResolutionReport','entries':[],'immutable_artifacts_mutated':False,'correction_requests_are_not_truth_sources':True})
 write_json_atomic(tmp/'errata_routing_plan.json',{'schema_version':'kfm.v1','object_type':'SoilErrataRoutingPlan','domain':'soil','resolution_id':rid,'accountability_id':aid,'release_id':rel_id,'errata_required':any(i['decision_type']=='errata' for i in items),'errata_items':[],'immutable_artifacts_mutated':False})
 write_json_atomic(tmp/'successor_release_plan.json',{'schema_version':'kfm.v1','object_type':'SoilSuccessorReleasePlan','domain':'soil','resolution_id':rid,'accountability_id':aid,'release_id':rel_id,'successor_release_required':any(i['decision_type']=='successor_release' for i in items),'successor_release_reason':'correction' if any(i['decision_type']=='successor_release' for i in items) else None,'planned_inputs':[],'proposed_successor_release_id':None,'reuse_prior_evidence_allowed':False,'requires_new_evidence_bundle':True,'requires_new_run_receipt':True,'requires_full_publication_chain':True,'immutable_prior_release_preserved':True,'created':utc_now_iso()})
 cert_action='none';
